mapper.update:
	UPDATE EVA_POOL_SCHE
 	SET
 	POOL_CD_NM = #{poolCdNm}
	,ST_DT = #{startDateTime} 
	,ED_DT = #{endDateTime}
	,STATUS_CD = #{statusCd}
	, LAST_CHNRG_ID = #{usrId}		
	, LAST_CHG_DT = sysdate
 	WHERE 
 		PERIOD_DIV_CD = #{periodDivCd}
	    AND EVA_YEAR = #{evaYear}
		AND POOL_CD = #{poolCd}

mapper.select:
SELECT
	COUNT(*)
FROM
	EVA_POOL_SCHE 
WHERE
	PERIOD_DIV_CD = #{periodDivCd}
	AND EVA_YEAR = #{evaYear}
	AND POOL_CD = #{poolCd}

mapper.delete:
DELETE FROM EVA_POOL_SCHE
WHERE
	PERIOD_DIV_CD = #{periodDivCd}
	AND EVA_YEAR = #{evaYear}
	AND POOL_CD = #{poolCd}

mapper.update:
	UPDATE EVA_POOL_APPL
 	SET
 	SEL_RSLT = #{selRslt}
	WHERE 
 		PERIOD_DIV_CD = #{periodDivCd}
	    AND EVA_YEAR = #{evaYear}
		AND POOL_CD = #{poolCd}
		AND DI = #{usrDi}
